let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { text: raw }; }

var ai = $.steps.parseAI.output;
var html = ai.html || ai.text || '';
var lineCount = html.split('\n').length;
var title = ai.title || 'Generated Webpage';
var desc = ai.description || $.input.pageDescription;
var features = ai.features || [];
var htmlPreview = html.slice(0, 2800);
var truncated = html.length > 2800;
return { html: html, htmlPreview: htmlPreview, truncated: truncated, lineCount: lineCount, title: title, description: desc, features: features };

var out = $.steps.prepareOutput.output;
var blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: ':globe_with_meridians: Generated Webpage: ' + out.title, emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: out.description } });
if (out.features.length > 0) {
  var featText = '*Features:*\n';
  out.features.forEach(function(f) { featText += ':white_check_mark: ' + f + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: featText } });
}
blocks.push({ type: 'divider' });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':page_facing_up: *HTML Code* (' + out.lineCount + ' lines)' } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '```' + out.htmlPreview + '```' } });
if (out.truncated) {
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: '_Code truncated. Full HTML is ' + out.html.length + ' characters._' }] });
}
blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':robot_face: Generated by Claude AI via One CLI' }] });
var fallback = 'Webpage Generated: ' + out.title + ' (' + out.lineCount + ' lines of HTML)';
return { blocks, fallback };
